-- study-notes.db schema
-- Master build artifact: NOT committed. Regenerated by build_study_notes.py.
-- Every work here is expected to be license_tier='quotation-only' (commercial
-- study Bible products) -- there is no open export of this domain, unlike
-- bible-text.db. Image files referenced by `images.file_path` live alongside
-- this db, under images/<work_id>/, never in git.

CREATE TABLE works (
    work_id TEXT PRIMARY KEY,
    title TEXT, publisher TEXT, year INTEGER,
    source_id TEXT, source_path TEXT, ingested_at TEXT,
    license TEXT, license_tier TEXT NOT NULL,
    attribution TEXT
);

CREATE TABLE verses (            -- this work's own base translation text (needed for context
    work_id TEXT NOT NULL REFERENCES works(work_id),   -- around notes; bible-text.db is the canonical text store)
    book TEXT NOT NULL, chapter INTEGER NOT NULL, verse INTEGER NOT NULL,
    text TEXT NOT NULL
);
CREATE INDEX idx_sn_verses_ref ON verses(book, chapter, verse);

CREATE TABLE introductions (
    work_id TEXT NOT NULL REFERENCES works(work_id),
    scope TEXT NOT NULL,             -- 'book' | 'section' | 'testament' | 'whole-bible'
    book TEXT,                        -- OSIS code, NULL unless scope='book'
    section_name TEXT,
    title TEXT NOT NULL,
    text TEXT NOT NULL
);
CREATE INDEX idx_intro_book ON introductions(book);

CREATE TABLE notes (
    work_id TEXT NOT NULL REFERENCES works(work_id),
    book TEXT NOT NULL,
    chapter INTEGER NOT NULL,
    verse_start INTEGER NOT NULL,
    verse_end INTEGER NOT NULL,
    note_type TEXT,                   -- 'footnote' | 'study_note' | 'cross_reference'
    text TEXT NOT NULL
);
CREATE INDEX idx_notes_ref ON notes(book, chapter, verse_start, verse_end);

CREATE TABLE topical_articles (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    work_id TEXT NOT NULL REFERENCES works(work_id),
    title TEXT NOT NULL,
    text TEXT NOT NULL
);

CREATE TABLE topical_article_refs (
    article_id INTEGER NOT NULL REFERENCES topical_articles(id),
    book TEXT NOT NULL, chapter INTEGER, verse INTEGER
);

CREATE TABLE images (
    work_id TEXT NOT NULL REFERENCES works(work_id),
    figure_id TEXT,
    book TEXT, chapter INTEGER, verse INTEGER,
    context_type TEXT,                -- 'introduction' | 'note' | 'topical_article' | 'standalone'
    file_path TEXT NOT NULL,           -- relative to images/<work_id>/
    caption TEXT,
    attribution TEXT,
    width INTEGER, height INTEGER
);
CREATE INDEX idx_images_ref ON images(book, chapter, verse);
